import React,{useState} from "react";
export default function Login(){
const[e,s]=useState("");const[p,sp]=useState("");
function login(){
if(e==="admin@gmail.com"&&p==="1234")
window.location="/dash"; else alert("Invalid");
}
return(<div className="box">
<h2>Sign In</h2>
<input placeholder="Email" onChange={v=>s(v.target.value)}/>
<input placeholder="Password" type="password" onChange={v=>sp(v.target.value)}/>
<button onClick={login}>Login</button>
</div>);
}
